CustomField.formula:
IF(INCLUDES(Statut__c, "Terminé"), "✅ Terminé",
    IF(INCLUDES(Statut__c, "Annulé"), "❌ Annulé",
        IF(INCLUDES(Statut__c, "En cours"), "🔵 En cours",
            IF(INCLUDES(Statut__c, "En attente"), "⏳ En attente", 
            "⚪ Statut non défini")
        )
    )
) 
& " | " &
IF(OR(ISBLANK(budget_c__c), ISBLANK(actual_cost__c)), "💰 Budget non renseigné",
    IF(actual_cost__c > budget_c__c, "🔴 DÉPASSEMENT BUDGET", 
        IF(actual_cost__c > (budget_c__c * 0.9), "🟠 SEUIL 90%", "🟢 Budget OK")
    )
) 
& " | " &
IF(OR(ISBLANK(startDate__c), ISBLANK(endDate__c)), "⚪ Dates non définies",
    /* Vérification globale du retard si le projet n'est pas fini/annulé */
    IF(AND(NOT(INCLUDES(Statut__c, "Terminé")), NOT(INCLUDES(Statut__c, "Annulé")), endDate__c < TODAY()), 
        "🚨 PROJET EN RETARD",
        IF(INCLUDES(Statut__c, "En cours"),
            IF((endDate__c - TODAY()) <= 3, "⚠️ FIN IMMINENTE", "📅 Planning OK"),
            IF(INCLUDES(Statut__c, "En attente"), 
                IF(TODAY() < startDate__c, "🕒 Attente démarrage", "⏳ En attente de début"),
                "🚀 Prêt pour lancement"
            )
        )
    )
)
